FINAL_ANSWER: import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data: return
    N, M, K = map(int, input_data[:3])
    idx = 3
    board = []
    for _ in range(9):
        board.append(list(map(int, input_data[idx:idx+9])))
        idx += 9
    stamps = []
    for _ in range(M):
        stamp = []
        for r in range(3):
            stamp.append(list(map(int, input_data[idx:idx+3])))
            idx += 3
        stamps.append(stamp)

    placements = []
    for m in range(M):
        for i in range(7):
            for j in range(7):
                possible = True
                for r in range(3):
                    for c in range(3):
                        if stamps[m][r][c] != 0 and board[i+r][j+c] != 0:
                            possible = False
                            break
                    if not possible: break
                if possible:
                    placements.append((m, i, j))
                    for r in range(3):
                        for c in range(3):
                            if stamps[m][r][c] != 0:
                                board[i+r][j+c] = 1
                    break

    print(len(placements))
    for p in placements:
        print(f"{p[0]} {p[1]} {p[2]}")

solve()

JUSTIFICATION: Python script implements greedy stamp placement on 9x9 board.
